/// <summary>sizeof = 8</summary>
public class PROTO_NC_MISC_ZONERINGLINKTEST_RNG
{
    public ZONERINGLINKAGESTART start = new();
    public byte mechines;
    public Name4[] addr = [];

    public void Read(BinaryReader reader)
    {
        start.Read(reader);
        mechines = reader.ReadByte();
        addr = new Name4[mechines];
        for (int i = 0; i < mechines; i++)
        {
            addr[i] = new Name4();
            addr[i].Read(reader);
        }
    }

    public void Write(BinaryWriter writer)
    {
        start.Write(writer);
        writer.Write(mechines);
        for (int i = 0; i < addr.Length; i++)
            addr[i].Write(writer);
    }

    public void Read(Stream stream) => Read(new BinaryReader(stream, System.Text.Encoding.UTF8, true));
    public void Write(Stream stream) => Write(new BinaryWriter(stream, System.Text.Encoding.UTF8, true));
}

